import React, { useState, useEffect } from 'react';
import {
  Grid,
  Card,
  CardContent,
  Typography,
  Box,
  LinearProgress,
  Chip,
  Avatar,
  IconButton,
  Paper,
} from '@mui/material';
import {
  TrendingUp,
  TrendingDown,
  Warning,
  CheckCircle,
  Refresh,
  Person,
  Timer,
  Analytics,
} from '@mui/icons-material';
import PostureChart from '../components/PostureChart';
import RealTimeMonitor from '../components/RealTimeMonitor';

const Dashboard = () => {
  const [postureData, setPostureData] = useState({
    currentPosture: 'Good',
    postureScore: 85,
    dailyAverage: 78,
    weeklyTrend: 5.2,
    sessionsToday: 8,
    totalTime: '6h 45m',
    riskLevel: 'Low',
  });

  const [recentAlerts, setRecentAlerts] = useState([
    { id: 1, type: 'warning', message: 'Poor posture detected for 15 minutes', time: '2 min ago' },
    { id: 2, type: 'info', message: 'Posture improved - Good job!', time: '1 hour ago' },
    { id: 3, type: 'success', message: 'Daily posture goal achieved', time: '3 hours ago' },
  ]);

  const StatCard = ({ title, value, subtitle, icon, color, trend }) => (
    <Card sx={{ height: '100%', position: 'relative', overflow: 'visible' }}>
      <CardContent>
        <Box sx={{ display: 'flex', alignItems: 'center', mb: 2 }}>
          <Avatar sx={{ bgcolor: `${color}.main`, mr: 2 }}>
            {icon}
          </Avatar>
          <Box sx={{ flexGrow: 1 }}>
            <Typography color="text.secondary" gutterBottom variant="body2">
              {title}
            </Typography>
            <Typography variant="h4" component="div" sx={{ fontWeight: 'bold' }}>
              {value}
            </Typography>
          </Box>
        </Box>
        
        {subtitle && (
          <Typography variant="body2" color="text.secondary">
            {subtitle}
          </Typography>
        )}
        
        {trend && (
          <Box sx={{ display: 'flex', alignItems: 'center', mt: 1 }}>
            {trend > 0 ? (
              <TrendingUp sx={{ color: 'success.main', mr: 0.5 }} />
            ) : (
              <TrendingDown sx={{ color: 'error.main', mr: 0.5 }} />
            )}
            <Typography 
              variant="body2" 
              sx={{ color: trend > 0 ? 'success.main' : 'error.main' }}
            >
              {Math.abs(trend)}% from last week
            </Typography>
          </Box>
        )}
      </CardContent>
    </Card>
  );

  const AlertItem = ({ alert }) => (
    <Box sx={{ display: 'flex', alignItems: 'center', p: 2, borderBottom: '1px solid', borderColor: 'divider' }}>
      <Avatar 
        sx={{ 
          bgcolor: alert.type === 'warning' ? 'warning.main' : 
                   alert.type === 'success' ? 'success.main' : 'info.main',
          mr: 2,
          width: 32,
          height: 32,
        }}
      >
        {alert.type === 'warning' ? <Warning /> : 
         alert.type === 'success' ? <CheckCircle /> : <Analytics />}
      </Avatar>
      <Box sx={{ flexGrow: 1 }}>
        <Typography variant="body2">{alert.message}</Typography>
        <Typography variant="caption" color="text.secondary">{alert.time}</Typography>
      </Box>
    </Box>
  );

  return (
    <Box>
      <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', mb: 3 }}>
        <Typography variant="h4" sx={{ fontWeight: 'bold', color: 'primary.main' }}>
          Dashboard
        </Typography>
        <IconButton color="primary" size="large">
          <Refresh />
        </IconButton>
      </Box>

      <Grid container spacing={3}>
        {/* Stats Cards */}
        <Grid item xs={12} sm={6} md={3}>
          <StatCard
            title="Current Posture"
            value={postureData.currentPosture}
            icon={<Person />}
            color="primary"
          />
        </Grid>
        
        <Grid item xs={12} sm={6} md={3}>
          <StatCard
            title="Posture Score"
            value={`${postureData.postureScore}%`}
            subtitle="Daily average: 78%"
            icon={<Analytics />}
            color="success"
            trend={postureData.weeklyTrend}
          />
        </Grid>
        
        <Grid item xs={12} sm={6} md={3}>
          <StatCard
            title="Active Time"
            value={postureData.totalTime}
            subtitle={`${postureData.sessionsToday} sessions today`}
            icon={<Timer />}
            color="info"
          />
        </Grid>
        
        <Grid item xs={12} sm={6} md={3}>
          <StatCard
            title="Risk Level"
            value={postureData.riskLevel}
            icon={<Warning />}
            color={postureData.riskLevel === 'Low' ? 'success' : 'warning'}
          />
        </Grid>

        {/* Real-time Monitor */}
        <Grid item xs={12} md={8}>
          <Card sx={{ height: 400 }}>
            <CardContent>
              <Typography variant="h6" gutterBottom>
                Real-time Posture Monitoring
              </Typography>
              <RealTimeMonitor />
            </CardContent>
          </Card>
        </Grid>

        {/* Recent Alerts */}
        <Grid item xs={12} md={4}>
          <Card sx={{ height: 400 }}>
            <CardContent sx={{ p: 0 }}>
              <Box sx={{ p: 2, borderBottom: '1px solid', borderColor: 'divider' }}>
                <Typography variant="h6">Recent Alerts</Typography>
              </Box>
              <Box sx={{ maxHeight: 320, overflow: 'auto' }}>
                {recentAlerts.map((alert) => (
                  <AlertItem key={alert.id} alert={alert} />
                ))}
              </Box>
            </CardContent>
          </Card>
        </Grid>

        {/* Posture Trends Chart */}
        <Grid item xs={12}>
          <Card>
            <CardContent>
              <Typography variant="h6" gutterBottom>
                Weekly Posture Trends
              </Typography>
              <PostureChart />
            </CardContent>
          </Card>
        </Grid>
      </Grid>
    </Box>
  );
};

export default Dashboard;
